export type VideoProjectState =
  | { status: "none" }
  | { status: "active"; id: string; title: string; scenes: number }
  | { status: "archived"; id: string; archivedAt: string };

export type VideoProjectCommand =
  | { type: "create"; id: string; title: string }
  | { type: "addScene" }
  | { type: "archive"; at: string }
  | { type: "reopen" };

export type VideoProjectEvent =
  | { type: "VideoProjectCreated"; id: string; title: string }
  | { type: "VideoProjectSceneAdded" }
  | { type: "VideoProjectArchived"; at: string }
  | { type: "VideoProjectReopened" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const videoProjectDecider: Decider<VideoProjectCommand, VideoProjectEvent, VideoProjectState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "VideoProjectCreated", id: command.id, title: command.title }];
      case "addScene":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "VideoProjectSceneAdded" }];
      case "archive":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "VideoProjectArchived", at: command.at }];
      case "reopen":
        if (state.status !== "archived") throw new DomainError("NOT_ARCHIVED");
        throw new DomainError("ARCHIVED_IMMUTABLE");
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "VideoProjectCreated":
        return { status: "active", id: event.id, title: event.title, scenes: 0 };
      case "VideoProjectSceneAdded":
        if (state.status !== "active") return state;
        return { ...state, scenes: state.scenes + 1 };
      case "VideoProjectArchived":
        if (state.status !== "active") return state;
        return { status: "archived", id: state.id, archivedAt: event.at };
      case "VideoProjectReopened":
        if (state.status !== "archived") return state;
        return state;
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
