export type EditSessionState =
  | { status: "none" }
  | { status: "open"; id: string; editor: string; pendingCuts: number }
  | { status: "committed"; id: string; editor: string; totalCuts: number }
  | { status: "discarded"; id: string };

export type EditSessionCommand =
  | { type: "open"; id: string; editor: string }
  | { type: "stageCut" }
  | { type: "commit"; at: string }
  | { type: "discard" };

export type EditSessionEvent =
  | { type: "EditSessionOpened"; id: string; editor: string }
  | { type: "EditSessionCutStaged" }
  | { type: "EditSessionCommitted"; at: string; totalCuts: number }
  | { type: "EditSessionDiscarded" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const editSessionDecider: Decider<EditSessionCommand, EditSessionEvent, EditSessionState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "EditSessionOpened", id: command.id, editor: command.editor }];
      case "stageCut":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "EditSessionCutStaged" }];
      case "commit":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (state.pendingCuts === 0) throw new DomainError("EMPTY");
        return [{ type: "EditSessionCommitted", at: command.at, totalCuts: state.pendingCuts }];
      case "discard":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        return [{ type: "EditSessionDiscarded" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "EditSessionOpened":
        return { status: "open", id: event.id, editor: event.editor, pendingCuts: 0 };
      case "EditSessionCutStaged":
        if (state.status !== "open") return state;
        return { ...state, pendingCuts: state.pendingCuts + 1 };
      case "EditSessionCommitted":
        if (state.status !== "open") return state;
        return { status: "committed", id: state.id, editor: state.editor, totalCuts: event.totalCuts };
      case "EditSessionDiscarded":
        if (state.status !== "open") return state;
        return { status: "discarded", id: state.id };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
