```typescript
export type RenderJobState =
  | { status: "none" }
  | { status: "queued"; id: string; sourceId: string }
  | { status: "running"; id: string; percent: number }
  | { status: "finished"; id: string; outputUri: string }
  | { status: "failed"; id: string; reason: string };

export type RenderJobCommand =
  | { type: "queue"; id: string; sourceId: string }
  | { type: "start" }
  | { type: "progress"; percent: number }
  | { type: "finish"; outputUri: string }
  | { type: "fail"; reason: string };

export type RenderJobEvent =
  | { type: "RenderJobQueued"; id: string; sourceId: string }
  | { type: "RenderJobStarted" }
  | { type: "RenderJobProgressed"; percent: number }
  | { type: "RenderJobFinished"; outputUri: string }
  | { type: "RenderJobFailed"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const renderJobDecider: Decider<RenderJobCommand, RenderJobEvent, RenderJobState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "queue":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "RenderJobQueued", id: command.id, sourceId: command.sourceId }];
      case "start":
        if (state.status !== "queued") throw new DomainError("NOT_QUEUED");
        return [{ type: "RenderJobStarted" }];
      case "progress":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        if (command.percent < 0 || command.percent > 100) throw new DomainError("BAD_PERCENT");
        return [{ type: "RenderJobProgressed", percent: command.percent }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "RenderJobFinished", outputUri: command.outputUri }];
      case "fail":
        if (state.status === "finished" || state.status === "failed") throw new DomainError("TERMINAL");
        return [{ type: "RenderJobFailed", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RenderJobQueued":
        return { status: "queued", id: event.id, sourceId: event.sourceId };
      case "RenderJobStarted":
        if (state.status !== "queued") return state;
        return { status: "running", id: state.id, percent: 0 };
      case "RenderJobProgressed":
        if (state.status !== "running") return state;
        return { ...state, percent: event.percent };
      case "RenderJobFinished":
        if (state.status !== "running") return state;
        return { status: "finished", id: state.id, outputUri: event.outputUri };
      case "RenderJobFailed":
        if (state.status === "none" || state.status === "finished" || state.status === "failed") return state;
        return { status: "failed", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
