export type SoundtrackCueState =
  | { status: "none" }
  | { status: "scheduled"; id: string; trackId: string; tcIn: number; muted: boolean }
  | { status: "finalized"; id: string; trackId: string; tcIn: number };

export type SoundtrackCueCommand =
  | { type: "schedule"; id: string; trackId: string; tcIn: number }
  | { type: "mute" }
  | { type: "unmute" }
  | { type: "finalize" };

export type SoundtrackCueEvent =
  | { type: "SoundtrackCueScheduled"; id: string; trackId: string; tcIn: number }
  | { type: "SoundtrackCueMuted" }
  | { type: "SoundtrackCueUnmuted" }
  | { type: "SoundtrackCueFinalized" };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const soundtrackCueDecider: Decider<SoundtrackCueCommand, SoundtrackCueEvent, SoundtrackCueState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.tcIn < 0) throw new DomainError("BAD_TC");
        return [{ type: "SoundtrackCueScheduled", id: command.id, trackId: command.trackId, tcIn: command.tcIn }];
      case "mute":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        if (state.muted) throw new DomainError("ALREADY_MUTED");
        return [{ type: "SoundtrackCueMuted" }];
      case "unmute":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        if (!state.muted) throw new DomainError("NOT_MUTED");
        return [{ type: "SoundtrackCueUnmuted" }];
      case "finalize":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        if (state.muted) throw new DomainError("MUTED");
        return [{ type: "SoundtrackCueFinalized" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SoundtrackCueScheduled":
        return { status: "scheduled", id: event.id, trackId: event.trackId, tcIn: event.tcIn, muted: false };
      case "SoundtrackCueMuted":
        if (state.status !== "scheduled") return state;
        return { ...state, muted: true };
      case "SoundtrackCueUnmuted":
        if (state.status !== "scheduled") return state;
        return { ...state, muted: false };
      case "SoundtrackCueFinalized":
        if (state.status !== "scheduled") return state;
        return { status: "finalized", id: state.id, trackId: state.trackId, tcIn: state.tcIn };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
