```typescript
export type SceneShotState =
  | { status: "none" }
  | { status: "logged"; id: string; sceneId: string; takes: number }
  | { status: "selected"; id: string; sceneId: string; takes: number; bestTake: number }
  | { status: "deleted"; id: string };

export type SceneShotCommand =
  | { type: "log"; id: string; sceneId: string }
  | { type: "recordTake" }
  | { type: "selectBest"; take: number }
  | { type: "deleteShot"; reason: string };

export type SceneShotEvent =
  | { type: "SceneShotLogged"; id: string; sceneId: string }
  | { type: "SceneShotTakeRecorded" }
  | { type: "SceneShotBestSelected"; take: number }
  | { type: "SceneShotDeleted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const sceneShotDecider: Decider<SceneShotCommand, SceneShotEvent, SceneShotState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "log":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "SceneShotLogged", id: command.id, sceneId: command.sceneId }];
      case "recordTake":
        if (state.status !== "logged" && state.status !== "selected") throw new DomainError("NOT_OPEN");
        return [{ type: "SceneShotTakeRecorded" }];
      case "selectBest":
        if (state.status !== "logged" && state.status !== "selected") throw new DomainError("NOT_OPEN");
        if (command.take < 1 || command.take > state.takes) throw new DomainError("OUT_OF_RANGE");
        return [{ type: "SceneShotBestSelected", take: command.take }];
      case "deleteShot":
        if (state.status === "deleted" || state.status === "none") throw new DomainError("BAD_STATE");
        return [{ type: "SceneShotDeleted", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SceneShotLogged":
        return { status: "logged", id: event.id, sceneId: event.sceneId, takes: 0 };
      case "SceneShotTakeRecorded":
        if (state.status !== "logged" && state.status !== "selected") return state;
        return { ...state, takes: state.takes + 1 };
      case "SceneShotBestSelected":
        if (state.status !== "logged" && state.status !== "selected") return state;
        return { status: "selected", id: state.id, sceneId: state.sceneId, takes: state.takes, bestTake: event.take };
      case "SceneShotDeleted":
        if (state.status === "none") return state;
        return { status: "deleted", id: "id" in state ? state.id : "" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
