```typescript
export type TranscriptEvent =
  | { type: "TranscriptStarted"; id: string; locale: string }
  | { type: "TranscriptSegmentAdded"; tStart: number; tEnd: number; text: string }
  | { type: "TranscriptSpeakerTagged"; tStart: number; speaker: string }
  | { type: "TranscriptPublished"; at: string }
  | { type: "RenderJobFinished"; outputUri: string };

export interface TranscriptView {
  readonly id: string;
  readonly locale: string;
  readonly segmentCount: number;
  readonly taggedSpeakers: readonly string[];
  readonly durationMs: number;
  readonly publishedAt: string | null;
}

export const emptyView: TranscriptView = {
  id: "",
  locale: "",
  segmentCount: 0,
  taggedSpeakers: [],
  durationMs: 0,
  publishedAt: null,
};

export function project(view: TranscriptView, event: TranscriptEvent): TranscriptView {
  switch (event.type) {
    case "TranscriptStarted":
      return { ...emptyView, id: event.id, locale: event.locale };
    case "TranscriptSegmentAdded":
      return {
        ...view,
        segmentCount: view.segmentCount + 1,
        durationMs: Math.max(view.durationMs, event.tEnd),
      };
    case "TranscriptSpeakerTagged":
      return view.taggedSpeakers.includes(event.speaker)
        ? view
        : { ...view, taggedSpeakers: [...view.taggedSpeakers, event.speaker] };
    case "TranscriptPublished":
      return { ...view, publishedAt: event.at };
    case "RenderJobFinished":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
