```typescript
export type CutListEvent =
  | { type: "CutListOpened"; id: string; projectId: string }
  | { type: "CutListCutAppended"; editor: string; durationMs: number }
  | { type: "CutListCutRemoved"; durationMs: number }
  | { type: "CutListLocked"; at: string }
  | { type: "EditSessionDiscarded" };

export interface CutListView {
  readonly id: string;
  readonly projectId: string;
  readonly totalCuts: number;
  readonly totalDurationMs: number;
  readonly lastEditor: string | null;
  readonly locked: boolean;
}

export const emptyView: CutListView = {
  id: "",
  projectId: "",
  totalCuts: 0,
  totalDurationMs: 0,
  lastEditor: null,
  locked: false,
};

export function project(view: CutListView, event: CutListEvent): CutListView {
  switch (event.type) {
    case "CutListOpened":
      return { ...emptyView, id: event.id, projectId: event.projectId };
    case "CutListCutAppended":
      return {
        ...view,
        totalCuts: view.totalCuts + 1,
        totalDurationMs: view.totalDurationMs + event.durationMs,
        lastEditor: event.editor,
      };
    case "CutListCutRemoved":
      return {
        ...view,
        totalCuts: Math.max(view.totalCuts - 1, 0),
        totalDurationMs: Math.max(view.totalDurationMs - event.durationMs, 0),
      };
    case "CutListLocked":
      return { ...view, locked: true };
    case "EditSessionDiscarded":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function aggregate(events: readonly CutListEvent[]): CutListView {
  return events.reduce(project, emptyView);
}
