```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface VideoProjectV1 {
  readonly id: string;
  readonly name: string;
}

export interface VideoProjectV2 {
  readonly id: string;
  readonly title: string;
  readonly scenes: number;
}

export interface VideoProjectV3 {
  readonly id: string;
  readonly title: string;
  readonly scenes: number;
  readonly archived: boolean;
}

export type CurrentVideoProject = VideoProjectV3;
export const CURRENT_VERSION = 3;

function v1Tov2(s: VideoProjectV1): VideoProjectV2 {
  return { id: s.id, title: s.name, scenes: 0 };
}

function v2Tov3(s: VideoProjectV2): VideoProjectV3 {
  return { ...s, archived: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentVideoProject> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as VideoProjectV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as VideoProjectV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${version}`);
  return { version, state: state as CurrentVideoProject };
}
