export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface RenderJobV1 {
  readonly id: string;
  readonly status: string;
  readonly outputUri?: string;
}

export type RenderJobV2 =
  | { status: "queued"; id: string }
  | { status: "running"; id: string }
  | { status: "finished"; id: string; outputUri: string };

export type RenderJobV3 =
  | { status: "queued"; id: string }
  | { status: "running"; id: string; percent: number }
  | { status: "finished"; id: string; outputUri: string };

export type CurrentRenderJob = RenderJobV3;
export const CURRENT_VERSION = 3;

function v1Tov2(s: RenderJobV1): RenderJobV2 {
  if (s.status === "queued") return { status: "queued", id: s.id };
  if (s.status === "running") return { status: "running", id: s.id };
  if (s.status === "finished") return { status: "finished", id: s.id, outputUri: s.outputUri ?? "" };
  throw new Error(`UNKNOWN_V1_STATUS_${s.status}`);
}

function v2Tov3(s: RenderJobV2): RenderJobV3 {
  if (s.status === "running") return { ...s, percent: 0 };
  return s;
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentRenderJob> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as RenderJobV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as RenderJobV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`BAD_VERSION_${version}`);
  return { version, state: state as CurrentRenderJob };
}
