  const state = loaded.events.reduce(evolve, initialState);
  const toAppend = produce(state);
  try {
    return await store.appendToStream(streamName, toAppend, { expectedRevision: loaded.revision });
  } catch (err) {
    throw new ConcurrencyConflict(streamName, loaded.revision);
