export type VideoProjectEvent =
  | { type: "VideoProjectCreated"; id: string; title: string }
  | { type: "VideoProjectArchived"; at: string };

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) {
    super(`conflict ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | "no_stream" }>;
  appendToStream(
    stream: string,
    events: E[],
    opts: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<bigint>;
}

export async function appendWithRetry(
  store: EventStore<VideoProjectEvent>,
  streamName: string,
  produce: (evts: VideoProjectEvent[]) => VideoProjectEvent[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const loaded = await store.readStream(streamName);
    const next = produce(loaded.events);
    try {
      return await store.appendToStream(streamName, next, { expectedRevision: loaded.revision });
    } catch {
      attempt += 1;
    }
  }
  throw new ConcurrencyConflict(streamName);
}
