  | { status: "open"; id: string; date: string; clips: readonly string[]; runtime: number }
  | { status: "approved"; id: string; date: string; clips: readonly string[]; runtime: number; by: string }
  | { status: "discarded"; id: string };

export function when(state: DailyRushState, event: DailyRushEvent): DailyRushState {
  switch (event.type) {
    case "DailyRushOpened":
      return { status: "open", id: event.id, date: event.date, clips: [], runtime: 0 };
    case "DailyRushClipAdded":
      if (state.status !== "open") return state;
      return { ...state, clips: [...state.clips, event.clipId], runtime: state.runtime + event.runtime };
    case "DailyRushApproved":
      if (state.status !== "open") return state;
      return { status: "approved", id: state.id, date: state.date, clips: state.clips, runtime: state.runtime, by: event.by };
    case "DailyRushDiscarded":
      if (state.status === "discarded" || state.status === "none") return state;
      return { status: "discarded", id: state.id };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function loadDailyRush(events: readonly DailyRushEvent[]): DailyRushState {
  return events.reduce(when, { status: "none" } as DailyRushState);
}
