  readonly locale: string;
  readonly segmentCount: number;
  readonly publishedAt: string | null;
}

export const emptyView: TranscriptView = { id: "", locale: "", segmentCount: 0, publishedAt: null };

export function project(view: TranscriptView, event: TranscriptEvent): TranscriptView {
  switch (event.type) {
    case "TranscriptStarted":
      return { ...emptyView, id: event.id, locale: event.locale };
    case "TranscriptSegmentAdded":
      return { ...view, segmentCount: view.segmentCount + 1 };
    case "TranscriptPublished":
      return { ...view, publishedAt: event.at };
