export interface EventBatch<E> {
  readonly events: readonly E[];
  readonly nextRevision: bigint;
  readonly endOfStream: boolean;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  readBatch: (from: bigint, batchSize: number) => Promise<EventBatch<TranscriptEvent>>;
  persist: (view: TranscriptView, position: bigint) => Promise<void>;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor = opts.from;
  let view = emptyView;
  for (;;) {
    const batch = await opts.readBatch(cursor, opts.batchSize);
    for (const event of batch.events) {
      view = project(view, event);
    }
    await opts.persist(view, batch.nextRevision);
    cursor = batch.nextRevision;
    if (batch.endOfStream) break;
  }
