export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export type VideoProjectState = { readonly scenes: number; readonly archived: boolean };

export type SceneCommand = { type: "addScene" };
export type SceneEvent = { type: "VideoProjectSceneAdded" };

export type ArchiveCommand = { type: "archive"; at: string };
export type ArchiveEvent = { type: "VideoProjectArchived"; at: string };

export type RoutedCommand =
  | { lane: "scene"; command: SceneCommand }
  | { lane: "archive"; command: ArchiveCommand };

export type RoutedEvent =
  | { lane: "scene"; event: SceneEvent }
  | { lane: "archive"; event: ArchiveEvent };

const sceneDecider: Decider<SceneCommand, SceneEvent, number> = {
  initialState: 0,
  decide: () => [{ type: "VideoProjectSceneAdded" }],
  evolve: (s, e) => (e.type === "VideoProjectSceneAdded" ? s + 1 : s),
};

const archiveDecider: Decider<ArchiveCommand, ArchiveEvent, boolean> = {
  initialState: false,
  decide: (c, s) => (s ? [] : [{ type: "VideoProjectArchived", at: c.at }]),
  evolve: (_s, e) => e.type === "VideoProjectArchived",
};

export const videoProjectDecider: Decider<RoutedCommand, RoutedEvent, VideoProjectState> = {
  initialState: { scenes: 0, archived: false },
  decide(command, state) {
    if (command.lane === "scene") {
      return sceneDecider.decide(command.command, state.scenes).map((event) => ({ lane: "scene", event }));
    }
    return archiveDecider.decide(command.command, state.archived).map((event) => ({ lane: "archive", event }));
  },
  evolve(state, event) {
    if (event.lane === "scene") {
      return { ...state, scenes: sceneDecider.evolve(state.scenes, event.event) };
    }
    return { ...state, archived: archiveDecider.evolve(state.archived, event.event) };
  },
};
