  | { code: "EXISTS" }
  | { code: "NOT_DRAFT" }
  | { code: "NO_LUT" }
  | { code: "UNKNOWN" };

export type DecideResult = { ok: true; events: ColorGradeEvent[] } | { ok: false; error: DomainError };

export function decide(command: ColorGradeCommand, state: ColorGradeState): DecideResult {
  switch (command.type) {
    case "create":
      if (state.status !== "none") return { ok: false, error: { code: "EXISTS" } };
      return { ok: true, events: [{ type: "ColorGradeCreated", id: command.id, shotId: command.shotId }] };
    case "applyLut":
      if (state.status !== "draft") return { ok: false, error: { code: "NOT_DRAFT" } };
      return { ok: true, events: [{ type: "ColorGradeLutApplied", lut: command.lut }] };
    case "approve":
      if (state.status !== "draft") return { ok: false, error: { code: "NOT_DRAFT" } };
      if (state.lut === null) return { ok: false, error: { code: "NO_LUT" } };
      return { ok: true, events: [{ type: "ColorGradeApproved", approvedBy: command.approvedBy, lut: state.lut }] };
    default: {
      const _never: never = command;
      return { ok: false, error: { code: "UNKNOWN" } };
    }
  }
}
