export type RenderJobEvent =
  | { type: "RenderJobQueued"; id: string }
  | { type: "RenderJobProgressed"; percent: number }
  | { type: "RenderJobFinished"; outputUri: string };

export type RenderJobState =
  | { status: "none" }
  | { status: "queued"; id: string; percent: number }
  | { status: "finished"; id: string; outputUri: string };

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
  readonly atStreamRevision: bigint;
}

export interface BuildSnapshotArgs {
  currentStreamVersion: bigint;
  lastSnapshotVersion: bigint | undefined;
  newEvent: RenderJobEvent;
  state: RenderJobState;
}

const SNAPSHOT_EVERY = 100n;
export const CURRENT_VERSION = 1;

export function buildSnapshot(args: BuildSnapshotArgs): Snapshot<RenderJobState> | null {
  const last = args.lastSnapshotVersion ?? 0n;
  if (args.currentStreamVersion - last < SNAPSHOT_EVERY) return null;
  if (args.newEvent.type !== "RenderJobFinished") return null;
  return {
    version: CURRENT_VERSION,
    state: args.state,
    atStreamRevision: args.currentStreamVersion,
  };
}
