```typescript
export type VideoProjectEvent =
  | { type: "VideoProjectCreated"; id: string; title: string }
  | { type: "VideoProjectArchived"; id: string; at: string };

export type IntegrationEvent =
  | { schema: "video.project.created.v1"; payload: { id: string; title: string } }
  | { schema: "video.project.archived.v1"; payload: { id: string; archivedAt: string } };

export interface OutboxRow {
  readonly id: string;
  readonly schema: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export function translate(event: VideoProjectEvent): IntegrationEvent | null {
  switch (event.type) {
    case "VideoProjectCreated":
      return { schema: "video.project.created.v1", payload: { id: event.id, title: event.title } };
    case "VideoProjectArchived":
      return { schema: "video.project.archived.v1", payload: { id: event.id, archivedAt: event.at } };
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface TxConnection<E> {
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" | "any" }): Promise<bigint>;
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export async function appendWithOutbox(
  tx: TxConnection<VideoProjectEvent>,
  streamName: string,
  events: readonly VideoProjectEvent[],
  expectedRevision: bigint | "no_stream" | "any",
  newOutboxId: () => string,
): Promise<bigint> {
  try {
    const rev = await tx.appendToStream(streamName, [...events], { expectedRevision });
    const rows: OutboxRow[] = [];
    for (const event of events) {
      const translated = translate(event);
      if (translated === null) continue;
      rows.push({
        id: newOutboxId(),
        schema: translated.schema,
        payload: JSON.stringify(translated.payload),
        publishedAt: null,
      });
    }
    if (rows.length > 0) await tx.insertOutbox(rows);
    await tx.commit();
    return rev;
  } catch (err) {
    await tx.rollback();
    throw err instanceof Error ? err : new Error(String(err));
  }
}
